Steps:
[AUTH role=ORG_USER]
[GQL-OP setup_me]
  query { me { id } }
[GQL-EXEC setup_me]
[GQL-CAPTURE setup_me.data.me.id → USER_ID]
[GQL-OP cleanup_pre]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" }) { id } }
[GQL-EXEC cleanup_pre]
[GQL-OP get_def]
  query { productConfiguration(configurableProductId: "@td(CFG_TEXT_DRIVEN_COND.id)" storeId: "{{STORE_ID}}" cultureName: "en-US") { configurationSections { id type isRequired maxLength allowCustomText } } }
[GQL-EXEC get_def]
[GQL-CAPTURE get_def.data.productConfiguration.configurationSections.0.id → SECTION_TEXT_ID]
[GQL-CAPTURE get_def.data.productConfiguration.configurationSections.0.maxLength → TEXT_MAX_LENGTH]
[GQL-OP add_item]
[GQL-VARS add_item] {"configurationSections": [{"sectionId": "{{SECTION_TEXT_ID}}", "type": "Text", "customText": "AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA"}]}
  mutation AddItem($configurationSections: [ConfigurationSectionInput]) {
    addItem(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" productId: "@td(CFG_TEXT_DRIVEN_COND.id)" quantity: 1 configurationSections: $configurationSections }) {
      id itemsCount items { id productId configurationItems { id sectionId customText } }
      validationErrors { errorCode errorMessage }
    }
  }
[GQL-EXEC add_item]
[GQL-CAPTURE add_item.data.addItem.items.0.id → LINE_ITEM_ID]
[GQL-OP change_at_max]
[GQL-VARS change_at_max] {"configurationSections": [{"sectionId": "{{SECTION_TEXT_ID}}", "type": "Text", "customText": "AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA"}]}
  mutation ChangeCartConfiguredItem($configurationSections: [ConfigurationSectionInput]) {
    changeCartConfiguredItem(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" lineItemId: "{{LINE_ITEM_ID}}" quantity: 1 configurationSections: $configurationSections }) {
      id validationErrors { errorCode errorMessage } items { id configurationItems { id sectionId customText } }
    }
  }
[GQL-EXEC change_at_max]
[GQL-OP cleanup_post]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" }) { id } }
[GQL-EXEC cleanup_post]

